import { put, call } from '@redux-saga/core/effects';
import { api } from '@semparar/mf-app-user';

import { PointsActions, PointsProduct } from '../../ducks/points';
import { eventServerResponse } from '~/constants/functions';
import { ProductResponse } from './models';

function extractConvertionFactor(products: PointsProduct[]): number {
  for (let i = 0; i < products.length; i++) {
    const product = products[i];

    if (product.convertionFactor && product.convertionFactor > 0) {
      return product.convertionFactor;
    }
  }

  return 0;
}

export function* getPointsProducts() {
  try {
    const response: ProductResponse = yield call(api.get, '/fintech/v1/rewardProgram/product', {});

    const products = response?.data?.data?.products ?? [];
    const returnCode =
      response?.data?.status?.returnCode ?? response?.data?.status?.codigoRetorno ?? 0;

    if (returnCode === 0) {
      eventServerResponse({
        content_type: 'sucesso',
        content_id: 'rewardprogram/v1/product-list',
        location_1: 'monetizacao',
        location_2: 'spmais',
        location_3: 'home',
      });
      yield put(PointsActions.successPointsProducts(products));

      const convertionFactor = extractConvertionFactor(products);
      yield put(PointsActions.setConversionFactor(convertionFactor));

      const invoiceProduct = products.find(
        (product) =>
          product.name?.toLowerCase().includes('fatura') ||
          product.action?.toLowerCase().includes('fatura')
      );

      if (invoiceProduct && invoiceProduct.conversionFactor) {
        yield put(PointsActions.setConversionFactor(invoiceProduct.conversionFactor));
      }

      eventServerResponse({
        content_type: 'sucesso',
        content_id: 'rewardprogram/v1/product-list',
        location_1: 'monetizacao',
        location_2: 'spmais',
        location_3: 'home',
      });
    } else {
      eventServerResponse({
        content_type: 'erro',
        content_id: 'rewardprogram/v1/product-list',
        location_1: 'monetizacao',
        location_2: 'spmais',
        location_3: 'home',
      });
      yield put(PointsActions.failedPointsProducts());

      eventServerResponse({
        content_type: 'erro',
        content_id: 'rewardprogram/v1/product-list',
        location_1: 'monetizacao',
        location_2: 'spmais',
        location_3: 'home',
      });
    }
  } catch (error) {
    eventServerResponse({
      content_type: 'erro',
      content_id: 'rewardprogram/v1/product-list',
      location_1: 'monetizacao',
      location_2: 'spmais',
      location_3: 'home',
    });
    yield put(PointsActions.failedPointsProducts());
  }
}

